        'volumeslider',
        'audio-volume',
        'audioCurrentTime',
        'audio-duration',
        'audioDuration',
        'settings',
        'lastFocusElement',
        'sessionid',
        'examid',
        'nextExamId',
        'previousExamId',
        'folder',
        'source',
        'result',
        'metadata',
        'practiceSettings'
