function summarizeMainErrorForLog(error) {
    const summary = {
        name: error && typeof error.name === 'string' ? error.name : 'Error'
    };
    if (error && typeof error.code === 'string' && /^[A-Za-z0-9_-]{1,64}$/.test(error.code)) {
        summary.code = error.code;
    }
    return summary;
}

